-- AXON results store (Cloudflare D1 / SQLite)
-- Run once:  npx wrangler d1 execute axon-db --remote --file=./schema.sql

CREATE TABLE IF NOT EXISTS results (
  id         INTEGER PRIMARY KEY AUTOINCREMENT,
  iq         INTEGER NOT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX IF NOT EXISTS idx_results_iq ON results(iq);

-- Seed ~320 synthetic scores (mean 100, SD 15) so early visitors
-- get a sensible live percentile. Real submissions blend in and
-- gradually dominate. Marked seed via created_at = 1970 sentinel.
